mapper.select:
/* com.erns.coching.url.mapper.shortUrlDAO.load */

SELECT

FROM T_SHORT_URL_INF AA

	AND AA.URL_ID = #{value, jdbcType=VARCHAR}

mapper.insert:
    	/* com.erns.coching.url.mapper.shortUrlDAO.insert */

    	INSERT INTO T_SHORT_URL_INF (
    		  URL_ID
    		, URL
    		, METHOD
			, PARAM_JSON
			, TOKEN

			, RGTR
			, RGT_DTTM
			, HITS
    	) VALUES (
			  #{urlId		, jdbcType=VARCHAR}
			, #{url			, jdbcType=VARCHAR}
			, #{method		, jdbcType=VARCHAR}
			, #{paramJson	, jdbcType=VARCHAR}
			, #{token		, jdbcType=VARCHAR}

			, #{rgtr		, jdbcType=INTEGER}
			, now()
			, 0
    	)

mapper.update:
/* com.erns.coching.url.mapper.shortUrlDAO.updateHits */

UPDATE T_SHORT_URL_INF
SET
	  HITS = HITS + 1
	, LAST_DTTM = now()

	AND URL_ID = #{value, jdbcType=VARCHAR}
